final:
module top_module(a,b,cin,sum,cout);input a,b,cin;
output sum,cout;
reg cout,m1,m2,m3;
wire carry_inverted;


xor x1(carry_inverted,a,b);


always @(a or b or cin) begin
    m1 = a & b;
    m2 = b & cin;
    m3 = a & cin;
    cout = (m1 | m2) | m3;
end


assign
    sum = carry_inverted ^ cin;

endmodule
